INSERT INTO agility_patterns (id, name, pattern_type, setup_description, cone_spacing_yards, total_distance_yards, direction_changes_count, execution_instructions, flag_football_application, created_at) VALUES (1, 'L-Drill Pro', 'l_drill', 'Set up L-shaped cone pattern: 5 yards forward, 5 yards lateral, 5 yards back', 5, 20, 3, '["Sprint 5 yards forward to first cone","Plant and cut right 90 degrees, sprint 5 yards","Plant and cut left 180 degrees, sprint 10 yards","Plant and cut right 90 degrees, sprint 5 yards to finish"]', 'Simulates route running with sharp cuts and direction changes', '2025-08-17T16:48:28.175Z');
INSERT INTO agility_patterns (id, name, pattern_type, setup_description, cone_spacing_yards, total_distance_yards, direction_changes_count, execution_instructions, flag_football_application, created_at) VALUES (2, 'Figure-8 Power', 'figure_8', 'Two cones 8 yards apart, sprint in figure-8 pattern', 8, 32, 6, '["Start at center between cones","Sprint to right cone, circle clockwise","Sprint to left cone, circle counter-clockwise","Complete two full figure-8 patterns"]', 'Develops curved running patterns for evasion and pursuit', '2025-08-17T16:48:28.237Z');
INSERT INTO agility_patterns (id, name, pattern_type, setup_description, cone_spacing_yards, total_distance_yards, direction_changes_count, execution_instructions, flag_football_application, created_at) VALUES (3, 'Reactive Flag Pull', 'reactive', 'Partner holds flags, runner reacts to partner movements', 0, 15, 4, '["Partner with flags moves laterally at 10-yard line","Runner mirrors movements while advancing","Partner signals direction changes every 2-3 steps","Runner must maintain forward progress while evading"]', 'Game-specific evasion training with unpredictable elements', '2025-08-17T16:48:28.291Z');
